import React, { useRef, useEffect } from 'react';
import { useLanguage } from '../contexts/LanguageContext';
import { getKeyboardConfig } from '../config/keyboardLoader';

const VirtualKeyboard = ({ activeKey, isCorrect }) => {
  const lastKeyRef = useRef(null);
  const lastCorrectRef = useRef(null);

  const { language } = useLanguage();
  const { layout: keyboardLayout, fingerMap, fingerNames } = getKeyboardConfig(language);

  useEffect(() => {
    if (isCorrect === null || isCorrect === undefined) return;
    if (lastKeyRef.current === activeKey && lastCorrectRef.current === isCorrect) return;
    lastKeyRef.current = activeKey;
    lastCorrectRef.current = isCorrect;
    if (isCorrect) playTick(); else playTock();
  }, [isCorrect, activeKey]);

  const playTick = () => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(900, ctx.currentTime);
      gain.gain.setValueAtTime(0.07, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.035);
      osc.start(ctx.currentTime); osc.stop(ctx.currentTime + 0.035);
      osc.onended = () => ctx.close();
    } catch (e) {}
  };

  const playTock = () => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'sine';
      osc.frequency.setValueAtTime(280, ctx.currentTime);
      gain.gain.setValueAtTime(0.06, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.055);
      osc.start(ctx.currentTime); osc.stop(ctx.currentTime + 0.055);
      osc.onended = () => ctx.close();
    } catch (e) {}
  };

  // ── Normalize a key entry to { id, label, wide } ─────────────────────────
  // English layout: each entry is a plain string e.g. 'a', 'SPACE', 'SHIFT_L'
  // Punjabi layout: each entry is an object e.g. { key: 'a', display: 'ਾ', wide: true }
  const normalize = (entry) => {
    if (typeof entry === 'string') {
      return { id: entry, label: entry, wide: false };
    }
    // Object format from Punjabi keyboard
    return {
      id:    entry.key     || '',
      label: entry.display || entry.key || '',
      wide:  entry.wide    || false,
    };
  };

  // ── Resolve fingerMap key ─────────────────────────────────────────────────
  // Try lowercase first, then as-is (for 'ShiftLeft', 'Enter', 'Backspace' etc.)
  const resolveFingerMap = (id) => {
    if (!id || typeof id !== 'string') return '';
    return fingerMap[id.toLowerCase()] || fingerMap[id] || '';
  };

  // ── Finger class for a key entry ──────────────────────────────────────────
  const getFingerClass = (entry) => {
    const { id } = normalize(entry);
    if (id === 'SPACE' || id === ' ') return fingerMap[' '] || '';
    return resolveFingerMap(id);
  };

  // ── Is this key entry the currently active key? ───────────────────────────
  const isActive = (entry) => {
    if (!activeKey) return false;
    const { id } = normalize(entry);
    if (id === 'SPACE' || id === ' ') return activeKey === ' ';
    if (typeof id !== 'string') return false;
    return id.toLowerCase() === activeKey.toLowerCase();
  };

  // ── Label for special English string keys ─────────────────────────────────
  const getLabel = (entry) => {
    const { id, label } = normalize(entry);
    if (id === 'SPACE')    return 'Space';
    if (id === 'SHIFT_L' || id === 'SHIFT_R' || id === 'ShiftLeft' || id === 'ShiftRight') return '⇧';
    if (id === 'ENTER'  || id === 'Enter')     return '↵';
    if (id === 'BACKSPACE' || id === 'Backspace') return '⌫';
    if (id === 'TAB'    || id === 'Tab')       return 'Tab';
    if (id === 'CAPS'   || id === 'CapsLock')  return 'Caps';
    return label;
  };

  // ── Wide key class ────────────────────────────────────────────────────────
  const getWideClass = (entry) => {
    const { id, wide } = normalize(entry);
    if (wide) return 'wide';
    // English string specials are also wide
    const wideKeys = ['BACKSPACE','TAB','CAPS','ENTER','SHIFT_L','SHIFT_R','SPACE'];
    return wideKeys.includes(id) ? id.toLowerCase().replace('_l','').replace('_r','') : '';
  };

  // ── Current finger tracking (for hand highlight) ──────────────────────────
  const isCapital = activeKey && activeKey !== activeKey.toLowerCase() && activeKey !== ' ';
  const baseLetter = activeKey ? activeKey.toLowerCase() : '';
  const currentFinger = activeKey
    ? (fingerMap[activeKey === ' ' ? ' ' : baseLetter] || resolveFingerMap(activeKey))
    : '';
  const currentFingerName = fingerNames[currentFinger] || '';
  const shiftFinger     = currentFinger.startsWith('left') ? 'right-pinky' : 'left-pinky';
  const shiftFingerName = fingerNames[shiftFinger];

  const leftFingerActive  = (f) => {
    if (isCapital && shiftFinger === `left-${f}`) return 'active';
    return currentFinger === `left-${f}` ? 'active' : '';
  };
  const rightFingerActive = (f) => {
    if (isCapital && shiftFinger === `right-${f}`) return 'active';
    return currentFinger === `right-${f}` ? 'active' : '';
  };
  const thumbActive = currentFinger === 'thumb' ? 'active' : '';

  return (
    <div className="virtual-keyboard">
      {/* Hand Guidance */}
      <div className="hand-guidance">
        <div className="left-hand">
          <div className="hand-icon">
            <div className={`fi pinky  ${leftFingerActive('pinky')}`} />
            <div className={`fi ring   ${leftFingerActive('ring')}`} />
            <div className={`fi middle ${leftFingerActive('middle')}`} />
            <div className={`fi index  ${leftFingerActive('index')}`} />
            <div className={`fi thumb  ${thumbActive}`} />
          </div>
        </div>

        <div className="finger-instruction">
          {currentFingerName && (
            <div className="finger-name-box">
              {isCapital ? (
                <>
                  <strong>Shift + {activeKey.toUpperCase()}</strong>
                  <span className="pill-divider">|</span>
                  <span>{shiftFingerName} + {currentFingerName}</span>
                </>
              ) : (
                <>
                  <strong>{activeKey === ' ' ? 'SPACE' : activeKey?.toUpperCase()}</strong>
                  <span className="pill-divider">|</span>
                  <span>{currentFingerName}</span>
                </>
              )}
            </div>
          )}
        </div>

        <div className="right-hand">
          <div className="hand-icon">
            <div className={`fi thumb  ${thumbActive}`} />
            <div className={`fi index  ${rightFingerActive('index')}`} />
            <div className={`fi middle ${rightFingerActive('middle')}`} />
            <div className={`fi ring   ${rightFingerActive('ring')}`} />
            <div className={`fi pinky  ${rightFingerActive('pinky')}`} />
          </div>
        </div>
      </div>

      {/* Keyboard Rows */}
      {keyboardLayout.map((row, ri) => (
        <div key={ri} className="keyboard-row">
          {row.map((entry, ki) => {
            const { id } = normalize(entry);
            return (
              <div
                key={`${ri}-${ki}-${id}`}
                className={`key ${getWideClass(entry)} ${getFingerClass(entry)} ${isActive(entry) ? 'active' : ''}`}
              >
                {getLabel(entry)}
              </div>
            );
          })}
        </div>
      ))}

      <div style={{ textAlign: 'center', marginTop: '0.4rem', color: '#9ca3af', fontSize: '0.72rem' }}>
        {language === 'punjabi'
          ? 'Home row: ੋ ੇ ੍ ਿ ੁ | ਪ ਰ ਕ ਤ ਚ'
          : 'Home row: A S D F | J K L ;'}
      </div>
    </div>
  );
};

export default VirtualKeyboard;
